+        policy_id: impl Into<String>,
+        now_unix_seconds: u64,
+        observations: Vec<RegressionObservation>,
+        waivers: Vec<RegressionWaiver>,
+    ) -> Self {
+        Self {
+            trace_id: trace_id.into(),
+            decision_id: decision_id.into(),
